noncompliant:
// Side effects in sizeof (not evaluated)
int counter = 0;
size_t size = sizeof(++counter); // Noncompliant: counter not incremented
printf("Counter: %d\n", counter); // Still 0

// Function call with side effects in sizeof
size_t arrSize = sizeof(getValue()); // Noncompliant: getValue() not called

// Side effects in unevaluated context
int x = 5;
int result = (true || ++x); // Noncompliant: ++x not evaluated due to short-circuit

// decltype with side effects (C++)
// decltype(++variable) type; // Noncompliant

compliant:
// No side effects in sizeof
int counter = 0;
int value = 42;
size_t size = sizeof(value); // OK: no side effects
++counter; // Explicit increment
printf("Counter: %d\n", counter);

// Use variables instead of function calls
int result = getValue();
size_t arrSize = sizeof(result); // OK: function called separately

// Avoid side effects in logical expressions
int x = 5;
if (true) {
    ++x; // Explicit increment when needed
}
int result = true; // Or assign directly

// Use explicit operations instead of relying on evaluation
